target.script:

var langstring = project.getProperty("langs");
if (langstring) {
  var tempIncludes = project.getProperty("dir.temp.includes");
  var langs = langstring.split(";");
  for (var i = 0; i < langs.length; i++) {
    if (langs[i] !== "") {
      var dir = new java.io.File(tempIncludes + "/" + langs[i]);
      dir.mkdirs();
    }
  }
}
